script:
# NOT a standalone script — this is the body of a Server Script record
# (Script Type: DocType Event, Reference: LedgerLift, Event: Before Save).
# Runs in Frappe's restricted safe-exec sandbox; only whitelisted methods used
# (frappe.utils, frappe.db.get_value, frappe.get_all, frappe.throw, _).

# 1. Days Outstanding — authoritative server-side calculation.
if doc.oldest_invoice_date:
    doc.days_outstanding = frappe.utils.date_diff(frappe.utils.nowdate(), doc.oldest_invoice_date) or 0
else:
    doc.days_outstanding = 0

# 2. Lock records already marked Paid — only administrators may modify.
#    The form client script only disables the UI; this is the real enforcement
#    (covers REST API, bulk edit and data import paths too).
if not doc.is_new():
    previous_status = frappe.db.get_value("LedgerLift Tracker", doc.name, "recovery_status")
    if previous_status == "Paid":
        user = frappe.session.user
        is_admin = user == "Administrator" or frappe.get_all(
            "Has Role",
            filters={"parent": user, "parenttype": "User", "role": "System Manager"},
            limit=1,
        )
        if not is_admin:
            frappe.throw(_("This LedgerLift record is marked Paid and locked. Only an administrator can modify it."))

# 3. Stamp / clear Paid On (drives the "Recovery This Month" number card).
if doc.recovery_status == "Paid" and not doc.paid_on:
    doc.paid_on = frappe.utils.nowdate()
if doc.recovery_status != "Paid" and doc.paid_on:
    doc.paid_on = None


# --- rolling follow-up sync (latest interaction row drives current next-action) ---
rows = doc.get("follow_ups") or []
if rows:
    last = None
    last_key = None
    for r in rows:
        key = (str(r.follow_up_date or "1900-01-01"), r.idx or 0)
        if last is None or key >= last_key:
            last = r
            last_key = key
    if last.follow_up_date:
        doc.last_contact_date = last.follow_up_date
    if last.next_follow_up_date:
        doc.next_follow_up_date = last.next_follow_up_date
    if last.promised_amount:
        doc.promised_amount = last.promised_amount
    if last.promised_date:
        doc.promised_payment_date = last.promised_date

count = frappe.db.count("LedgerLift Tracker", {
    "recovery_status": ["!=", "Paid"],
    "next_follow_up_date": ["<=", frappe.utils.nowdate()],
})
frappe.response["message"] = count

s = frappe.get_doc("StockPilot Settings")
if frappe.utils.cint(s.freeze_classes):
    months = frappe.utils.cint(s.class_freeze_months)
    if months < 1:
        months = 3
    refresh = 0
    if not s.frozen_on:
        refresh = 1
    elif frappe.utils.date_diff(frappe.utils.nowdate(), frappe.utils.add_months(s.frozen_on, months)) >= 0:
        refresh = 1
    if refresh:
        res = frappe.get_doc("Report", "StockPilot Categories").execute_script_report({"view": "raw"})
        mp = {}
        for r in res[1]:
            cc = (r.get("m") or "C") + (r.get("v") or "C")
            mp[r.get("code")] = [cc, frappe.utils.flt(r.get("a12"))]
        s.frozen_class_map = json.dumps(mp)
        s.frozen_on = frappe.utils.nowdate()
        s.save()
